use crate::db::{get_db_connection, Email};
use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};

#[derive(Debug, Serialize, Deserialize)]
pub struct FilterEmailsParams {
    pub account: String,
    pub folder: String,
    pub subject_patterns: Vec<String>,
    #[serde(default = "default_match_mode")]
    pub match_mode: MatchMode,
    pub sender_filter: Option<String>,
    pub recipient_filter: Option<String>,
    pub date_after: Option<DateTime<Utc>>,
    pub date_before: Option<DateTime<Utc>>,
    #[serde(default = "default_max_results")]
    pub max_results: Option<usize>,
}

#[derive(Debug, Serialize, Deserialize)]
pub enum MatchMode {
    #[serde(rename = "any")]
    Any,
    #[serde(rename = "all")]
    All,
}

fn default_match_mode() -> MatchMode { MatchMode::Any }
fn default_max_results() -> Option<usize> { Some(500) }

#[derive(Debug, Serialize)]
pub struct FilteredEmail {
    pub uid: u32,
    pub subject: String,
    pub from_address: String,
    pub to_addresses: Vec<String>,
    pub date: DateTime<Utc>,
    pub has_attachments: bool,
    pub matched_patterns: Vec<String>,
}

#[derive(Debug, Serialize)]
pub struct FilterEmailsResult {
    pub account: String,
    pub folder: String,
    pub patterns_used: Vec<String>,
    pub match_mode: MatchMode,
    pub total_matched: usize,
    pub results: Vec<FilteredEmail>,
}

pub async fn filter_emails_by_subject(params: FilterEmailsParams) -> Result<FilterEmailsResult> {
    let conn = get_db_connection(&params.account).await?;

    // Build SQL query with joins
    let mut query = String::from(
        "SELECT e.uid, e.subject, e.from_address, e.to_addresses, e.date, e.has_attachments 
         FROM emails e 
         JOIN folders f ON e.folder_id = f.id 
         WHERE f.name = ?"
    );

    let mut bindings = vec![params.folder.clone()];

    // Add subject pattern conditions
    if !params.subject_patterns.is_empty() {
        let pattern_conditions = match params.match_mode {
            MatchMode::Any => {
                let conditions: Vec<String> = params.subject_patterns.iter()
                    .map(|_| "e.subject LIKE ?")
                    .collect();
                format!(" AND ({})", conditions.join(" OR "))
            },
            MatchMode::All => {
                let conditions: Vec<String> = params.subject_patterns.iter()
                    .map(|_| "e.subject LIKE ?")
                    .collect();
                format!(" AND {}", conditions.join(" AND "))
            }
        };
        query.push_str(&pattern_conditions);

        // Add pattern bindings with SQL wildcards
        for pattern in &params.subject_patterns {
            bindings.push(format!("%{}%", pattern));
        }
    }

    // Add optional filters
    if let Some(sender) = &params.sender_filter {
        query.push_str(" AND e.from_address LIKE ?");
        bindings.push(format!("%{}%", sender));
    }

    if let Some(recipient) = &params.recipient_filter {
        query.push_str(" AND e.to_addresses LIKE ?");
        bindings.push(format!("%{}%", recipient));
    }

    if let Some(date_after) = params.date_after {
        query.push_str(" AND e.date >= ?");
        bindings.push(date_after.to_rfc3339());
    }

    if let Some(date_before) = params.date_before {
        query.push_str(" AND e.date <= ?");
        bindings.push(date_before.to_rfc3339());
    }

    // Order by date descending
    query.push_str(" ORDER BY e.date DESC");

    // Add limit
    let limit = params.max_results.unwrap_or(500);
    query.push_str(&format!(" LIMIT {}", limit));

    // Execute query
    let rows = sqlx::query(&query)
        .bind_values(&bindings)
        .fetch_all(&conn)
        .await?;

    // Process results
    let mut results = Vec::new();
    for row in rows {
        let subject: String = row.get("subject");

        // Determine which patterns matched
        let matched_patterns: Vec<String> = params.subject_patterns.iter()
            .filter(|pattern| subject.to_lowercase().contains(&pattern.to_lowercase()))
            .cloned()
            .collect();

        results.push(FilteredEmail {
            uid: row.get("uid"),
            subject,
            from_address: row.get("from_address"),
            to_addresses: serde_json::from_str(&row.get::<String, _>("to_addresses"))?,
            date: DateTime::parse_from_rfc3339(&row.get::<String, _>("date"))?.with_timezone(&Utc),
            has_attachments: row.get("has_attachments"),
            matched_patterns,
        });
    }

    Ok(FilterEmailsResult {
        account: params.account,
        folder: params.folder,
        patterns_used: params.subject_patterns,
        match_mode: params.match_mode,
        total_matched: results.len(),
        results,
    })
}
