use crate::db::{get_db_connection, Email};
use html2text::from_read;
use serde::{Deserialize, Serialize};
use chrono::{DateTime, Utc};

#[derive(Debug, Serialize, Deserialize)]
pub struct BatchGetSynopsisParams {
    pub account: String,
    pub folder: String,
    pub uids: Vec<u32>,
    pub max_chars_per_synopsis: Option<usize>,
}

#[derive(Debug, Serialize)]
pub struct BatchSynopsisResult {
    pub account: String,
    pub folder: String,
    pub requested: usize,
    pub returned: usize,
    pub synopses: Vec<EmailSynopsis>,
    pub errors: Vec<ErrorItem>,
}

#[derive(Debug, Serialize)]
pub struct EmailSynopsis {
    pub uid: u32,
    pub subject: String,
    pub from_address: String,
    pub to_addresses: Vec<String>,
    pub date: DateTime<Utc>,
    pub has_attachments: bool,
    pub synopsis: String,
}

#[derive(Debug, Serialize)]
pub struct ErrorItem {
    pub uid: u32,
    pub reason: String,
}

pub async fn batch_get_synopsis(params: BatchGetSynopsisParams) -> Result<BatchSynopsisResult> {
    // Validate UID count
    if params.uids.len() > 50 {
        return Err("Maximum 50 UIDs per batch".into());
    }

    let max_chars = params.max_chars_per_synopsis.unwrap_or(300).min(800);

    // Query SQLite cache
    let conn = get_db_connection(&params.account).await?;

    let mut synopses = vec![];
    let mut errors = vec![];

    // Build query for multiple UIDs
    let placeholders = params.uids.iter().map(|_| "?").collect::<Vec<_>>().join(",");
    let query = format!(
        "SELECT uid, subject, from_address, to_addresses, date, has_attachments, body_text 
         FROM emails 
         WHERE folder = ? AND uid IN ({})",
        placeholders
    );

    let mut stmt = conn.prepare(&query)?;
    let mut query_params: Vec<Box<dyn ToSql>> = vec![Box::new(&params.folder)];
    for uid in &params.uids {
        query_params.push(Box::new(uid));
    }

    let email_iter = stmt.query_map(&query_params[..], |row| {
        Ok(Email {
            uid: row.get(0)?,
            subject: row.get(1)?,
            from_address: row.get(2)?,
            to_addresses: serde_json::from_str(&row.get::<_, String>(3)?).unwrap_or_default(),
            date: row.get(4)?,
            has_attachments: row.get(5)?,
            body_text: row.get(6)?,
        })
    })?;

    let mut found_uids = HashSet::new();

    for email_result in email_iter {
        match email_result {
            Ok(email) => {
                found_uids.insert(email.uid);
                let synopsis = generate_synopsis(&email.body_text, max_chars);

                synopses.push(EmailSynopsis {
                    uid: email.uid,
                    subject: email.subject,
                    from_address: email.from_address,
                    to_addresses: email.to_addresses,
                    date: email.date,
                    has_attachments: email.has_attachments,
                    synopsis,
                });
            }
            Err(e) => {
                // Handle row errors
                errors.push(ErrorItem {
                    uid: 0, // Unknown UID
                    reason: e.to_string(),
                });
            }
        }
    }

    // Add errors for UIDs not found
    for &uid in &params.uids {
        if !found_uids.contains(&uid) {
            errors.push(ErrorItem {
                uid,
                reason: "UID not found in cache".to_string(),
            });
        }
    }

    // Sort synopses to match input order
    let uid_order: HashMap<u32, usize> = params.uids.iter()
        .enumerate()
        .map(|(i, &uid)| (uid, i))
        .collect();

    synopses.sort_by_key(|s| uid_order.get(&s.uid).copied().unwrap_or(usize::MAX));

    Ok(BatchSynopsisResult {
        account: params.account,
        folder: params.folder,
        requested: params.uids.len(),
        returned: synopses.len(),
        synopses,
        errors,
    })
}

fn generate_synopsis(body_text: &str, max_chars: usize) -> String {
    // Strip HTML if present
    let text_content = if body_text.trim_start().starts_with('<') {
        from_read(body_text.as_bytes(), 80)
    } else {
        body_text.to_string()
    };

    // Take first ~500 chars, then truncate to max_chars
    let preview = if text_content.len() > 500 {
        &text_content[..500]
    } else {
        &text_content
    };

    // Clean up whitespace and truncate
    let cleaned = preview
        .lines()
        .map(|line| line.trim())
        .filter(|line| !line.is_empty())
        .collect::<Vec<_>>()
        .join(" ");

    if cleaned.len() > max_chars {
        let mut end = max_chars;
        while end > 0 && !cleaned.is_char_boundary(end) {
            end -= 1;
        }

        // Find last space for clean break
        if let Some(last_space) = cleaned[..end].rfind(' ') {
            end = last_space;
        }

        format!("{}...", &cleaned[..end].trim())
    } else {
        cleaned
    }
}
