use thiserror::Error;
use tracing::{error, warn, info, debug};

#[derive(Error, Debug)]
pub enum RustymailError {
    #[error("IMAP connection error for account {account}: {source}")]
    ImapConnection {
        account: String,
        #[source]
        source: imap::Error,
    },

    #[error("Authentication failed for {account}")]
    AuthenticationFailed {
        account: String,
        details: String,
    },

    #[error("Folder '{folder}' not found in account {account}")]
    FolderNotFound {
        account: String,
        folder: String,
    },

    #[error("Export failed: {reason}")]
    ExportFailed {
        reason: String,
        #[source]
        source: Option<Box<dyn std::error::Error + Send + Sync>>,
    },

    #[error("Invalid parameter: {param} - {reason}")]
    InvalidParameter {
        param: String,
        reason: String,
    },

    #[error("IO error: {context}")]
    Io {
        context: String,
        #[source]
        source: std::io::Error,
    },
}

// Result type alias
pub type Result<T> = std::result::Result<T, RustymailError>;

// Context trait for adding context to errors
pub trait ErrorContext<T> {
    fn context(self, msg: &str) -> Result<T>;
    fn with_context<F>(self, f: F) -> Result<T>
    where
        F: FnOnce() -> String;
}

impl<T, E> ErrorContext<T> for std::result::Result<T, E>
where
    E: Into<RustymailError>,
{
    fn context(self, msg: &str) -> Result<T> {
        self.map_err(|e| {
            let base_error = e.into();
            error!("{}: {:?}", msg, base_error);
            base_error
        })
    }

    fn with_context<F>(self, f: F) -> Result<T>
    where
        F: FnOnce() -> String,
    {
        self.map_err(|e| {
            let context = f();
            let base_error = e.into();
            error!("{}: {:?}", context, base_error);
            base_error
        })
    }
}
