pub struct AttachmentInfo {
    pub filename: Option<String>,
    pub content_type: String,
    pub size: u64,
    pub part_id: String,
    pub disposition: String,
}

// Update fetch_email to include attachment parsing
pub async fn fetch_email(&mut self, uid: u32) -> Result<Email> {
    let messages = self.session
        .uid_fetch(uid.to_string(), "(UID FLAGS INTERNALDATE RFC822.SIZE ENVELOPE BODY.PEEK[] BODYSTRUCTURE)")?
        .collect::<Result<Vec<_>, _>>()?;

    let msg = messages.first().ok_or("Email not found")?;
    let bodystructure = msg.bodystructure()
        .ok_or("Missing BODYSTRUCTURE")?;

    // Parse attachments from BODYSTRUCTURE
    let attachments = parse_attachments_from_bodystructure(bodystructure);

    // ... existing email parsing ...

    Ok(Email {
        // ... existing fields ...
        attachments: Some(attachments),
    })
}

fn parse_attachments_from_bodystructure(body: &BodyStructure) -> Vec<AttachmentInfo> {
    let mut attachments = Vec::new();
    parse_body_recursive(body, "", &mut attachments);
    attachments
}

fn parse_body_recursive(body: &BodyStructure, part_path: &str, attachments: &mut Vec<AttachmentInfo>) {
    match body {
        BodyStructure::Multipart { bodies, .. } => {
            for (idx, sub_body) in bodies.iter().enumerate() {
                let sub_path = if part_path.is_empty() {
                    (idx + 1).to_string()
                } else {
                    format!("{}.{}", part_path, idx + 1)
                };
                parse_body_recursive(sub_body, &sub_path, attachments);
            }
        }
        BodyStructure::Basic { 
            common, 
            specific,
            extension,
            ..
        } => {
            // Check if this is an attachment
            let is_attachment = extension.as_ref()
                .and_then(|ext| ext.disposition.as_ref())
                .map(|disp| disp.disposition.to_lowercase() == "attachment")
                .unwrap_or(false);

            // Also check for non-text/html parts in multipart messages
            let content_type = format!("{}/{}", common.media_type, common.media_subtype);
            let is_likely_attachment = !content_type.starts_with("text/") || is_attachment;

            if is_likely_attachment && part_path != "1" {  // Skip main body
                let filename = extension.as_ref()
                    .and_then(|ext| ext.disposition.as_ref())
                    .and_then(|disp| disp.params.as_ref())
                    .and_then(|params| params.get("filename"))
                    .cloned()
                    .or_else(|| {
                        common.params.as_ref()
                            .and_then(|p| p.get("name"))
                            .cloned()
                    });

                attachments.push(AttachmentInfo {
                    filename,
                    content_type,
                    size: common.size.unwrap_or(0) as u64,
                    part_id: part_path.to_string(),
                    disposition: extension.as_ref()
                        .and_then(|ext| ext.disposition.as_ref())
                        .map(|d| d.disposition.clone())
                        .unwrap_or_else(|| "inline".to_string()),
                });
            }
        }
        _ => {}
    }
}
