                        .cloned();

                    attachments.push(AttachmentMetadata {
                        filename,
                        content_type: format!("{}/{}", ty, subtype),
                        size: body.octets(),
                        content_id: body.id().map(|s| s.to_string()),
                    });
                }
            }
        }
        _ => {}
    }

    attachments
}
